'use client';

import React, { useState } from 'react';
import { 
  Calendar, 
  Search, 
  ChevronRight,
  UserX,
  AlertCircle
} from 'lucide-react';

// Mock Data Interfaces
interface Driver {
  id: string;
  name: string;
  phone: string;
  type: 'Regular' | 'Charter';
  vehicleNumber: string;
}

interface Dispatch {
  id: string;
  driverId: string;
  date: string; // YYYY-MM-DD
}

// Mock Data
const MOCK_DRIVERS: Driver[] = [
  { id: '1', name: '김철수', phone: '010-1234-5678', type: 'Regular', vehicleNumber: '11가 1234' },
  { id: '2', name: '이영희', phone: '010-2345-6789', type: 'Regular', vehicleNumber: '22나 2345' },
  { id: '3', name: '박건우', phone: '010-3456-7890', type: 'Charter', vehicleNumber: '33다 3456' }, // Charter should be excluded
  { id: '4', name: '정민수', phone: '010-4567-8901', type: 'Regular', vehicleNumber: '44라 4567' },
];

const MOCK_DISPATCHES: Dispatch[] = [
  // Kim (Regular) worked on 2024-02-12 (Mon)
  { id: 'd1', driverId: '1', date: '2024-02-12' },
  // Lee (Regular) missed 2024-02-12 (Mon)
  // Jung (Regular) worked on 2024-02-12 (Mon)
  { id: 'd2', driverId: '4', date: '2024-02-12' },
];

  import { getAbsenceData, AbsenceRecord } from './actions';

  export default function VehicleAbsencePage() {
    const [startDate, setStartDate] = useState('2024-02-01');
    const [endDate, setEndDate] = useState('2024-02-29');
    const [results, setResults] = useState<AbsenceRecord[]>([]);
    const [isSearching, setIsSearching] = useState(false);

    const handleSetThisMonth = () => {
      const now = new Date();
      const start = new Date(now.getFullYear(), now.getMonth(), 1);
      const end = new Date(now.getFullYear(), now.getMonth() + 1, 0);
      setStartDate(formatDate(start));
      setEndDate(formatDate(end));
    };

    const handleSetPrevMonth = () => {
      const now = new Date();
      const start = new Date(now.getFullYear(), now.getMonth() - 1, 1);
      const end = new Date(now.getFullYear(), now.getMonth(), 0);
      setStartDate(formatDate(start));
      setEndDate(formatDate(end));
    };

    const formatDate = (date: Date) => {
      const y = date.getFullYear();
      const m = String(date.getMonth() + 1).padStart(2, '0');
      const d = String(date.getDate()).padStart(2, '0');
      return `${y}-${m}-${d}`;
    };

    const handleSearch = async () => {
      setIsSearching(true);
      try {
        const data = await getAbsenceData(startDate, endDate);
        setResults(data);
      } catch (error) {
        console.error(error);
        alert('데이터 조회 중 오류가 발생했습니다.');
      } finally {
        setIsSearching(false);
      }
    };

  return (
    <div className="space-y-6 relative max-w-[1200px] mx-auto">
      {/* Sticky Filter Bar */}
      <div className="sticky top-0 z-30 py-4 bg-slate-100/95 backdrop-blur-md transition-all">
        <div className="flex items-center justify-between mb-4">
           {/* Simple Header as requested */}
           <div className="flex items-center gap-2">
              <div className="p-2 bg-rose-100 rounded-lg text-rose-600">
                <UserX size={20} />
              </div>
              <h2 className="text-lg font-bold text-slate-800">차량 결근 조회</h2>
           </div>
        </div>

        <div className="glass rounded-2xl border border-white shadow-sm p-4 flex flex-wrap items-center justify-between gap-4">
          <div className="flex items-center gap-4">
            {/* Date Range Picker */}
            <div className="flex items-center gap-2 bg-white px-4 py-2 rounded-xl border border-slate-200 shadow-sm">
              <Calendar size={16} className="text-indigo-500" />
              <div className="flex items-center gap-2">
                <input 
                  type="date" 
                  value={startDate}
                  onChange={(e) => setStartDate(e.target.value)}
                  className="bg-transparent border-none text-[13px] font-bold text-slate-700 focus:ring-0 cursor-pointer outline-none"
                />
                <ChevronRight size={14} className="text-slate-300" />
                <input 
                  type="date" 
                  value={endDate}
                  onChange={(e) => setEndDate(e.target.value)}
                  className="bg-transparent border-none text-[13px] font-bold text-slate-700 focus:ring-0 cursor-pointer outline-none"
                />
              </div>
            </div>

            {/* Helper Buttons */}
            <div className="flex gap-1.5 bg-slate-200/50 p-1 rounded-xl">
              <button 
                onClick={handleSetThisMonth}
                className="px-3 py-1.5 text-[12px] font-bold text-slate-600 hover:bg-white hover:text-indigo-600 hover:shadow-sm rounded-lg transition-all"
              >
                당월
              </button>
              <button 
                onClick={handleSetPrevMonth}
                className="px-3 py-1.5 text-[12px] font-bold text-slate-600 hover:bg-white hover:text-indigo-600 hover:shadow-sm rounded-lg transition-all"
              >
                전월
              </button>
            </div>
          </div>

          <button 
            onClick={handleSearch}
            disabled={isSearching}
            className="flex items-center gap-2 px-6 py-2.5 bg-rose-600 text-white rounded-xl text-[13px] font-bold hover:bg-rose-700 transition-all active:scale-95 shadow-md shadow-rose-200 disabled:opacity-50"
          >
            {isSearching ? (
              <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
            ) : (
              <Search size={16} />
            )}
            조회하기
          </button>
        </div>
      </div>

      {/* Results Section */}
      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden min-h-[400px]">
        {results.length > 0 ? (
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-slate-50 border-b border-slate-200">
                  <th className="px-6 py-4 text-[12px] font-bold text-slate-500 uppercase">결근 일자</th>
                  <th className="px-6 py-4 text-[12px] font-bold text-slate-500 uppercase">요일</th>
                  <th className="px-6 py-4 text-[12px] font-bold text-slate-500 uppercase">기사명</th>
                  <th className="px-6 py-4 text-[12px] font-bold text-slate-500 uppercase">차량번호</th>
                  <th className="px-6 py-4 text-[12px] font-bold text-slate-500 uppercase">연락처</th>
                  <th className="px-6 py-4 text-[12px] font-bold text-slate-500 uppercase text-center">상태</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {results.map((record, idx) => (
                  <tr key={idx} className="hover:bg-slate-50 transition-colors group">
                    <td className="px-6 py-4 text-[13px] font-bold text-slate-700">{record.date}</td>
                    <td className="px-6 py-4 text-[13px] font-medium text-slate-600">
                      <span className={`px-2 py-1 rounded text-[11px] font-bold ${
                        record.dayOfWeek === '토' ? 'bg-blue-50 text-blue-600' : 
                        record.dayOfWeek === '일' ? 'bg-rose-50 text-rose-600' : 
                        'bg-slate-100 text-slate-500'
                      }`}>
                        {record.dayOfWeek}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-[13px] font-bold text-slate-800">{record.driverName}</td>
                    <td className="px-6 py-4 text-[13px] font-medium text-slate-600 bg-slate-50/50 rounded-lg">{record.vehicleNumber}</td>
                    <td className="px-6 py-4 text-[13px] font-mono text-slate-500">{record.phone}</td>
                    <td className="px-6 py-4 text-center">
                      <span className="px-2.5 py-1 rounded-full bg-rose-50 text-rose-600 text-[11px] font-bold border border-rose-100">
                        결근 (No Dispatch)
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center h-[400px] text-slate-400">
            <div className="p-4 bg-slate-50 rounded-full mb-3">
              <AlertCircle size={32} className="text-slate-300" />
            </div>
            <p className="font-medium text-sm">조회된 결근 데이터가 없습니다.</p>
            <p className="text-xs text-slate-400 mt-1">조회 버튼을 눌러 데이터를 확인하세요.</p>
          </div>
        )}
      </div>

      <div className="flex justify-end text-[11px] text-slate-400">
        <p>* 정규 기사(용차 제외) 중 월~금 배차 기록이 없는 경우를 조회합니다. (Mock Data Version)</p>
      </div>
    </div>
  );
}
